/**
 * International Foods Import Script
 *
 * Imports ~300 internationally popular foods with realistic nutrition data.
 * Covers Canadian specialties and cuisines from Japan, Mexico, India, China,
 * Korea, Middle East, Italy, Thailand, Ethiopia, Caribbean, Africa, and Britain.
 *
 * Usage:
 *   npx ts-node scripts/import-international.ts
 */

import db from "../src/data/database";
import { calculateNutriScore } from "../src/services/nutrition-score";
import { detectAllergens, detectDietaryTags } from "../src/services/food-analysis";

// ─── Types ───────────────────────────────────────────────────────────────────

interface FoodEntry {
  name: string;
  brand: string | null;
  category: string;
  serving_size: number;
  serving_unit: string;
  calories: number;
  total_fat: number;
  saturated_fat: number;
  trans_fat: number;
  cholesterol: number;
  sodium: number;
  total_carbohydrates: number;
  dietary_fiber: number;
  total_sugars: number;
  protein: number;
  ingredients_text: string | null;
}

// ─── Upsert Statement ───────────────────────────────────────────────────────

const upsert = db.prepare(`
  INSERT INTO foods (id, name, brand, category, serving_size, serving_unit, source,
    calories, total_fat, saturated_fat, trans_fat, cholesterol, sodium,
    total_carbohydrates, dietary_fiber, total_sugars, protein,
    ingredients_text, allergens, dietary_tags, nutri_score, nutri_grade,
    updated_at)
  VALUES (@id, @name, @brand, @category, @serving_size, @serving_unit, 'usda',
    @calories, @total_fat, @saturated_fat, @trans_fat, @cholesterol, @sodium,
    @total_carbohydrates, @dietary_fiber, @total_sugars, @protein,
    @ingredients_text, @allergens, @dietary_tags, @nutri_score, @nutri_grade,
    datetime('now'))
  ON CONFLICT(id) DO UPDATE SET
    name = excluded.name,
    brand = excluded.brand,
    category = excluded.category,
    serving_size = excluded.serving_size,
    serving_unit = excluded.serving_unit,
    calories = excluded.calories,
    total_fat = excluded.total_fat,
    saturated_fat = excluded.saturated_fat,
    trans_fat = excluded.trans_fat,
    cholesterol = excluded.cholesterol,
    sodium = excluded.sodium,
    total_carbohydrates = excluded.total_carbohydrates,
    dietary_fiber = excluded.dietary_fiber,
    total_sugars = excluded.total_sugars,
    protein = excluded.protein,
    ingredients_text = excluded.ingredients_text,
    allergens = excluded.allergens,
    dietary_tags = excluded.dietary_tags,
    nutri_score = excluded.nutri_score,
    nutri_grade = excluded.nutri_grade,
    updated_at = datetime('now')
`);

const upsertBatch = db.transaction((foods: Record<string, unknown>[]) => {
  for (const f of foods) upsert.run(f);
});

// ─── Helper ──────────────────────────────────────────────────────────────────

function prepareRow(id: string, food: FoodEntry): Record<string, unknown> {
  const allergens = food.ingredients_text ? detectAllergens(food.ingredients_text) : [];
  const dietaryTags = detectDietaryTags(food.ingredients_text || "", {
    total_carbohydrates: food.total_carbohydrates,
    protein: food.protein,
    total_fat: food.total_fat,
    total_sugars: food.total_sugars,
    dietary_fiber: food.dietary_fiber,
  });
  const nutriScore = calculateNutriScore(
    {
      calories: food.calories,
      totalSugars: food.total_sugars,
      saturatedFat: food.saturated_fat,
      sodium: food.sodium,
      dietaryFiber: food.dietary_fiber,
      protein: food.protein,
    },
    food.category
  );

  return {
    id,
    name: food.name,
    brand: food.brand,
    category: food.category,
    serving_size: food.serving_size,
    serving_unit: food.serving_unit,
    calories: food.calories,
    total_fat: food.total_fat,
    saturated_fat: food.saturated_fat,
    trans_fat: food.trans_fat,
    cholesterol: food.cholesterol,
    sodium: food.sodium,
    total_carbohydrates: food.total_carbohydrates,
    dietary_fiber: food.dietary_fiber,
    total_sugars: food.total_sugars,
    protein: food.protein,
    ingredients_text: food.ingredients_text,
    allergens: allergens.length > 0 ? allergens.join(",") : null,
    dietary_tags: dietaryTags.length > 0 ? dietaryTags.join(",") : null,
    nutri_score: nutriScore.score,
    nutri_grade: nutriScore.grade,
  };
}

