// ─── Main Import ─────────────────────────────────────────────────────────────

function importRegion(regionId: string, regionName: string, foods: FoodEntry[]) {
  const rows = foods.map((food, idx) => {
    const id = `intl-${regionId}-${String(idx + 1).padStart(3, "0")}`;
    return prepareRow(id, food);
  });

  upsertBatch(rows);
  console.log(`  ${regionName}: ${rows.length} foods imported`);
  return rows.length;
}

function main() {
  console.log("=== International Foods Import ===\n");

  const beforeCount = (db.prepare("SELECT COUNT(*) as c FROM foods").get() as any).c;
  console.log(`Total foods in DB before: ${beforeCount}\n`);

  let total = 0;

  total += importRegion("ca", "Canadian", canadianFoods);
  total += importRegion("jp", "Japanese", japaneseFoods);
  total += importRegion("mx", "Mexican", mexicanFoods);
  total += importRegion("in", "Indian", indianFoods);
  total += importRegion("cn", "Chinese", chineseFoods);
  total += importRegion("kr", "Korean", koreanFoods);
  total += importRegion("me", "Middle Eastern", middleEasternFoods);
  total += importRegion("it", "Italian", italianFoods);
  total += importRegion("th", "Thai", thaiFoods);
  total += importRegion("et", "Ethiopian", ethiopianFoods);
  total += importRegion("cb", "Caribbean", caribbeanFoods);
  total += importRegion("af", "African", africanFoods);
  total += importRegion("gb", "British", britishFoods);

  // Rebuild FTS index
  console.log("\nRebuilding search index...");
  db.exec("INSERT INTO foods_fts(foods_fts) VALUES('rebuild')");

  const afterCount = (db.prepare("SELECT COUNT(*) as c FROM foods").get() as any).c;
  console.log(`\n=== Done! ===`);
  console.log(`International foods imported: ${total}`);
  console.log(`Total foods before: ${beforeCount}`);
  console.log(`Total foods after:  ${afterCount}`);
  console.log(`Net new foods:      ${afterCount - beforeCount}`);
}

main();
